SELECT fl.factory_line_id, fl.factory_line_name, COUNT(DISTINCT o.order_id) AS total_order_count, SUM(CASE WHEN o.order_status = 'COMPLETED' THEN 1 ELSE 0 END) AS completed_count, ROUND( SUM(CASE WHEN o.order_status = 'COMPLETED' THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(DISTINCT o.order_id), 0), 1 ) AS achievement_rate FROM factory_line fl JOIN equipment_process ep ON fl.factory_line_id = ep.factory_line_id JOIN equipment eq ON ep.equipment_process_id = eq.equipment_process_id JOIN worker_deployment wd ON eq.equipment_id = wd.equipment_id AND wd.employee_id IN
#{id}
AND (wd.end_date IS NULL OR wd.end_date >= CURDATE()) LEFT JOIN matching_record mr ON wd.employee_id = mr.employee_id AND DATE(mr.created_at) BETWEEN wd.start_date AND COALESCE(wd.end_date, CURDATE()) LEFT JOIN orders o ON mr.order_id = o.order_id GROUP BY fl.factory_line_id, fl.factory_line_name
